import { defer, of, share } from 'rxjs';

// COLD: each subscriber triggers a new HTTP request.
const cold$ = this.http.get('/api/config');
cold$.subscribe(a => console.log('A', a)); // request #1
cold$.subscribe(b => console.log('B', b)); // request #2 (duplicate!)

// HOT via share(): one execution multicast to all subscribers.
const hot$ = this.http.get('/api/config').pipe(share());
hot$.subscribe(a => console.log('A', a)); // triggers request
hot$.subscribe(b => console.log('B', b)); // joins the SAME request

// defer() proves laziness: the factory runs per subscription.
const lazy$ = defer(() => of(Date.now()));

