}

import { Subject, BehaviorSubject, ReplaySubject, AsyncSubject } from 'rxjs';

const s = new Subject<number>();
s.subscribe(v => console.log('S', v));
s.next(1); // S 1 (subscriber present)

const b = new BehaviorSubject<number>(0); // seeded
b.next(1);
b.subscribe(v => console.log('B', v)); // B 1 (gets current value immediately)

const r = new ReplaySubject<number>(2); // buffer last 2
r.next(1); r.next(2); r.next(3);
r.subscribe(v => console.log('R', v)); // R 2, R 3

const a = new AsyncSubject<number>();
a.subscribe(v => console.log('A', v));
a.next(1); a.next(2);
a.complete(); // A 2 (only the last, only on complete)

// Reading a marble diagram for map(x => x * 10):
// source:  --1--2--3|
// map:      --10-20-30|

// Reading debounceTime(20):
// source:  a-b-c------d--|   (a,b,c are close together)
// output:  ---------c----d|  (only the last of a burst survives)

// Grouped sync emissions: (abc) all happen in one frame
// merge of --a--b and --c--d might yield --(ac)--(bd)

import { of, interval } from 'rxjs';
import { map, scan, take } from 'rxjs';

// map: transform each value
of(1, 2, 3).pipe(map(x => x * 10)); // 10, 20, 30

// scan: running accumulator (emits every step)
interval(1000).pipe(
  scan((acc, _cur) => acc + 1, 0)
); // 1, 2, 3, ... a running count

// pluck alternative: map + optional chaining (pluck is deprecated)
interface User { profile?: { name?: string } }
of<User>({ profile: { name: 'Ada' } }).pipe(
  map(u => u.profile?.name ?? 'anonymous')
); // 'Ada'

