import { Observable, of } from 'rxjs';
import {
  debounceTime, distinctUntilChanged, filter,
  switchMap, catchError, map, startWith
} from 'rxjs';

interface SearchState<T> {
  loading: boolean;
  results: T[];
  error: boolean;
}

export function createTypeahead<T>(
  term$: Observable<string>,
  search: (q: string) => Observable<T[]>
): Observable<SearchState<T>> {
  return term$.pipe(
    map(t => t.trim()),
    debounceTime(300),
    distinctUntilChanged(),
    filter(q => q.length >= 2),
    switchMap(q =>
      search(q).pipe(
        map(results => ({ loading: false, results, error: false })),
        startWith({ loading: true, results: [], error: false }),
        catchError(() =>
          of({ loading: false, results: [], error: true })
        )
      )
    ),
    startWith({ loading: false, results: [], error: false })
  );
}

