import { Observable, of } from 'rxjs';
import { exhaustMap, tap, catchError, finalize, map } from 'rxjs';

interface SaveResult<R> {
  ok: boolean;
  data?: R;
  error?: unknown;
}

export function createSaveHandler<P, R>(
  clicks$: Observable<void>,
  getPayload: () => P,
  save: (p: P) => Observable<R>,
  setSaving: (v: boolean) => void
): Observable<SaveResult<R>> {
  return clicks$.pipe(
    exhaustMap(() => {
      setSaving(true);
      return save(getPayload()).pipe(
        map<R, SaveResult<R>>(data => ({ ok: true, data })),
        catchError(error => of<SaveResult<R>>({ ok: false, error })),
        finalize(() => setSaving(false))
      );
    })
  );
}

