import { Observable, forkJoin, of } from 'rxjs';
import { catchError, map } from 'rxjs';

interface User { id: string; name: string; }
interface Order { id: string; total: number; }
interface DashboardVm {
  user: User | null;
  permissions: string[];
  orders: Order[];
}

export function loadDashboard(
  getUser: () => Observable<User>,
  getPermissions: () => Observable<string[]>,
  getOrders: () => Observable<Order[]>
): Observable<DashboardVm> {
  return forkJoin({
    user: getUser().pipe(catchError(() => of(null))),
    permissions: getPermissions().pipe(catchError(() => of([] as string[]))),
    orders: getOrders().pipe(catchError(() => of([] as Order[]))),
  }).pipe(
    map(({ user, permissions, orders }) => ({ user, permissions, orders }))
  );
}

