import { Observable, timer, throwError } from 'rxjs';
import { retry, catchError } from 'rxjs';

function isRetryable(error: any): boolean {
  const status = error?.status ?? 0;
  // Retry network/5xx; do NOT retry 4xx client errors.
  return status === 0 || status >= 500;
}

export function withBackoff<T>(
  request$: Observable<T>,
  maxRetries = 3,
  baseMs = 500
): Observable<T> {
  return request$.pipe(
    retry({
      count: maxRetries,
      delay: (error, attempt) => {
        if (!isRetryable(error)) {
          return throwError(() => error); // stop retrying 4xx immediately
        }
        const backoff = baseMs * Math.pow(2, attempt - 1);
        const jitter = Math.random() * baseMs;
        return timer(backoff + jitter);
      },
    }),
    catchError(err =>
      throwError(() => new Error('Request failed after retries: ' + (err?.message ?? err)))
    )
  );
}

import { Observable, of } from 'rxjs';
import { concatMap, distinctUntilChanged, catchError, map } from 'rxjs';

interface DocState { version: number; body: string; }
interface Ack { version: number; ok: boolean; error?: unknown; }

export function createAutosaveQueue(
  edits$: Observable<DocState>,
  save: (s: DocState) => Observable<void>
): Observable<Ack> {
  return edits$.pipe(
    distinctUntilChanged(
      (a, b) => a.body === b.body // skip identical consecutive snapshots
    ),
    concatMap(state =>
      save(state).pipe(
        map<void, Ack>(() => ({ version: state.version, ok: true })),
        catchError(error =>
          of<Ack>({ version: state.version, ok: false, error })
        )
      )
    )
  );
}

// concatMap guarantees each save finishes before the next begins, preserving order.
